(function(){
  var ckWrap = qSel('#ckWrap'), 
      ckAccept = qSel('#ckAccept');

  if (ckWrap && ckAccept) {
    ckWrap.classList.add('v');

    ckAccept.onclick = () => {
      document.cookie = 'CookiePolicy=Accepted;max-age=' + PuSet.cookieCon.consentMaxAge + ';path=/';
      if (document.cookie.indexOf('CookiePolicy=Accepted') !== -1) {
        ckWrap.classList.add('a');
      } else {
        fixedNotif(PuSet.cookieCon.cookieError);
        if ('vibrate' in navigator) { navigator.vibrate([100,75,100,75,500]); }
      }
    };

    if (document.cookie.indexOf('CookiePolicy=Accepted') !== -1) {
      ckWrap.classList.remove('v');
    }
  }
})();
